import{_ as p,o as e,c as a,j as r,a as t,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const L=JSON.parse('{"title":"枪刃系列","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/7.系列武器/枪刃系列 .md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/7.系列武器/枪刃系列 .md"}'),s={name:"4.资源分区/7.物品与装备/2.武器/近战武器/7.系列武器/枪刃系列 .md"};function n(o,b,_,l,c,i){return e(),a("div",null,[...b[0]||(b[0]=[r("h1",{id:"枪刃系列",tabindex:"-1"},[t("枪刃系列 "),r("a",{class:"header-anchor",href:"#枪刃系列","aria-label":'Permalink to "枪刃系列"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),d('<h1 id="枪刃系列-1" tabindex="-1">枪刃系列 <a class="header-anchor" href="#枪刃系列-1" aria-label="Permalink to &quot;枪刃系列&quot;">​</a></h1><p>枪刃系列<br> 概述：该系列武器收录了风格迥异的各类【枪刃】可供枪刃战士们使用挑选，并提供了枪刃的基础模板，其共同性是所有的【枪刃】都只有6发装弹上限，并切拥有刃的形状和左轮的转轮特征，把手处略微弯曲呈现枪柄与扳机形状，转轮仅是用于储存晶弹，通常而言并没有直接开火射击的能力。</p><p>基础模板：</p><p>枪刃<br> 价格：100<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：3L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹量：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹</p><p>晶弹储存匣<br> 价格：100<br> 用于储存晶弹的特制匣子，里面存储着无限的晶弹，同时只能取出至多6枚，换弹依然需要自身手动进行。</p><p>ps：枪刃的基础装弹动作为移动动作，无法以任何能力获得武器上的无限子弹（即必须主动换弹），武器伤害提供的破防类型为破甲，并且所有基于枪刃的武器伤害提供的破甲都仅在攻击消耗了至少1枚晶弹后生效。</p><p>无支线：</p><p>幻化枪刃<br> 价格：10<br> 效果：这是一种不占据武器位的特殊概念武装，仅能附着在分类为【枪刃】的武器上，拥有该概念武装的枪刃战士可以随意挑选枪刃系列（或其它分类为【枪刃】的武器）中与自身最高内在强化等级相同或更低支线等级的武器外观，并使该外观附着在使用的枪刃上，这仅是画风效果，不会导致属性和武器特性的改变。</p><p>D级：</p><p>黄铜左轮刃<br> 科技本质<br> 价格：D+500<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：6L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 效果：这是一把铜黄色的枪刃，极具维多利亚时期的蒸汽朋克风格，转轮非常突出，并单独开辟了一个射击用的枪口，可以视为【左轮手枪】一般进行射击，消耗晶弹造成物理-穿刺伤害，基础特性与左轮手枪无异，若如此做则在攻击时使用手枪专业。无论如何，以该武器进行的攻击总是额外具有1点附加成功，攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。</p><p>硬钢枪刃<br> 科技本质<br> 价格：D+500<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：6L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。<br> 效果：这是一柄筒体漆黑的坚硬枪刃，整体呈流线型，坚实可靠，朴实无华。使用该武器攻击时可以自由动作消耗1颗晶弹进行加速推动，使这次攻击视为【短点射】并附带1点附加成功，对敌人额外造成2点多次攻击减值。</p><p>鬼船枪刃<br> 魔幻本质<br> 价格：D+500<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：6L<br> 伤害类型 ：见下<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。<br> 效果：这是一柄如海盗弯刃般的枪刃，转轮形似燧发枪（燧发枪有转轮吗？（别管这么多），锈迹斑斑的刀刃散发着浓郁明显的海腥味与铁锈味，持握时会感觉到一阵阴凉。持握该武器会为持有者提供【灵感视觉】，并且只有持有者或其它具有灵感视觉者看得到的是，会有一只半透明的骷髅骨掌与持有者的手一起抓着这把武器，因此，该武器中附着的船员之魂会帮助你攻击到幽灵，这视为一个【法破】特性。</p><p>地狱犬枪刃<br> 特异本质<br> 价格：D+500<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：6L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 效果：这是一把由猩红的血肉与带有烧焦痕迹的锋利甲壳构成的活体枪刃，晶弹转轮其实是这把武器的内脏，因挥动而被唤醒的地狱犬之魂会从刃处刺出利齿，撕扯敌人，填饱自身。这把武器具有【吸血1】，并在攻击时提供2dp器械加值，攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。</p><p>C级</p><p>阎魔枪刃<br> 魔幻本质<br> 价格：C+1000<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：11L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。<br> 效果：这把枪刃的把手与刀背由黑玉构成，刀刃则是血玉雕琢，锋锐异常，金色的护手与转轮镌刻着朱砂梵文，只有当主人陷入危险时，这把武器才会兴奋地醒来。仅当使用者的生命值中不存在任何完好时，该武器上的梵文散发出刺眼的红光，其立即为持有者提供【狂怒3】，并在攻击时提供2dp器械加值。</p><p>曼德维尔魔导刃<br> 魔幻本质<br> 价格：C+1000<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：11L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲3<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。<br> 效果：由曼德威尔魔导军工出品的第一代枪刃，其极具科技感的外观与刃面上流动的魔力条纹深受消费者喜爱，曼德维尔魔导军工还加装了快速填装系统，辅助战士们在战场上更加流畅地战斗。<br> 该武器在每轮进行的首次攻击时，会根据目前转轮内晶弹的剩余数量来提供加成，<br> 若剩余晶弹数量为6~3枚，则为本轮的攻击提供1dp器械加值与1点附加成功；<br> 若剩余晶弹数量为2~0枚，则该回合装填晶弹时下降一级装弹动作，并在格挡防御上获得1点附加成功。<br> 以该武器造成伤害时可以选择其中1点严重伤害转变为韧性，被该武器攻击者将会承受8点魔力流失。</p><p>异怪枪刃<br> 特异本质<br> 价格：C+1000<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：11L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。<br> 效果：这是一柄由漆黑的生物质缠绕而成的活体枪刃，持握时，这些黑色的触须末端会紧紧吸取着你的手掌，因此不会被击落武器，战斗开始后每经过一回合都会在攻击上获得1dp器械加值，至多因此获益5次，这把武器总是会为你的攻击提供【高速2】。</p><p>总督枪刃<br> 科技本质<br> 价格：C+1000<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：11L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。<br> 效果：这把枪刃来源于一位失踪的星际总督，由超越晶体物质硬度阈值的半透明宇宙晶体作为刀刃，华贵的黄铜工艺构造全身，持握的手感一流，但这把枪刃的每一任持有者最后都遭到了至亲朋友的背刺。以该武器进行攻击时可以消耗1点意志，若如此做，这次攻击额外具有1dp器械加值，承受该武器攻击者需针对那次攻击出目进行强韧豁免，若豁免失败则承受持续一轮的强韧豁免上的【劣化1】与1点物理-挥砍伤害易伤。</p><p>沼泽女巫枪刃<br> 魔幻本质<br> 价格：C+1000<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：11L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。<br> 描述：曾有一位沼泽女巫在战斗中被人活活抵挡完了所有的魔力后战败，回去之后她痛定思痛，用爆炸蘑菇的菌丝、沼泽食人魔的肋骨、毒沼蛙的毒素、流涎柳的枝条和碳化的巨茸树干做成了这把非常“自然”的“魔杖”，在之后的决斗中，她和对手耗完了魔力，然后追着对方砍了三条街，赢下了决斗。<br> 效果：这是一坨仿佛是烂木、菌丝、苔藓和地衣组成的绿化带中延伸出由柳条和白色骨骼组成的刀刃，一般情况下认不出这东西到底有什么杀伤力，所以在攻击时，总是具有C级措手不及效果，进入战斗后的一、二、三回合会获得不同的效果，效果相互替换，根据回合数不断循环，第一回合会使攻击额外附带持续一轮的1点物理-挥砍易伤，第二回合会为自身提供1点快速医疗（12医疗点数），第三回合在攻击时会具有1点附加成功。</p><p>炀火枪刃<br> 魔幻本质<br> 价格：C+1000<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：11L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。<br> 描述：古书记载，有龙化人，名炀火，好冶炼锻造，与凡人交，诞三子。为庆长子成年，铸此刃，刃长三尺余，形似砍刀，黑身白刃，有红须交缠刀柄，活铁似火，攀附刃身，握之灼手，留炀火之名，新年后。<br> 效果：使用这把武器进行的攻击若消耗了晶弹则额外具有1点不可豁免的燃烧点数，并对敌人造成持续一轮的1点火焰伤害易伤，可以在攻击前将至多3点破甲转化为破魔。</p><p>B级：</p><p>陨铁重刃<br> 科技本质<br> 价格：B+2000<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：18L<br> 伤害类型 ：物理-挥砍<br> 力量需求：15<br> 武器体积：3<br> 装弹：6<br> 基础特性：沉重 攻击时若消耗了至少1枚晶弹则获得破甲2<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。<br> 效果：这是由天外陨铁打造的漆黑枪刃，在日光照射下刀刃具有彩虹般的反光，极其沉重。以这把武器进行攻击时，其势大力沉，可以为这次攻击提供等同于力量属性点的器械加值与额外1点附加成功，以这把武器进行格挡时，其坚硬无比，可以为这次格挡提供等同于力量属性点一半的格挡防御与额外1点近战伤害吸收。</p><p>三头地狱犬<br> 特异本质<br> 价格：B+2000<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：18L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。<br> 特殊的，该武器可以通过D级的地狱犬枪刃差价购买而来。<br> 效果：这是一把由猩红的血肉与带有烧焦痕迹的锋利甲壳构成的活体枪刃，洁白的骨骼组成了晶弹转轮，而其中装填着的蠕动晶弹其实是这把武器的内脏，因挥动而被唤醒的三头地狱犬之魂会从刃处刺出三条长满利齿的椎骨，撕扯敌人，填饱自身。<br> 该武器在进行白刃攻击时可以延伸出三条椎骨刀刃，提升15米触及范围，攻击额外具有【吸血4】【破甲10】，并具有【湮灭】特性。</p><p>灾厄月食<br> 魔幻本质<br> 价格：B+2000<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：18L<br> 伤害类型 ：见下<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。<br> 这是一把白刃、红身、黑柄的直刀枪刃，转轮内的晶弹呈现新月至满月的变化。挥动之时，刀刃划过的轨迹显露出一片仿佛被吞噬的漆黑。<br> 这把武器具有【9加骰】，在挥砍时具有【熔毁5】，虽然刀刃造成的光效是一片漆黑，但其攻击造成的伤害会转变为光能伤害，攻击在伤害结算时可以选择至多5点严重伤害转化为韧性，这是一个来源于【能量武器】特性的效果。<br> 在换弹时，这把武器会依次切换刀刃的颜色，基础为白色，根据刀刃的颜色，在攻击上获得不同的加成：<br> 白刃：攻击具有【高速15】<br> 黑刃：攻击具有1点附加成功，【法破】和【破魔5】，计算破防后，若还有剩余的破魔，则可以转化为攻击上的器械加值，至多转化5点破魔。<br> 红刃：攻击具有【吸血3】，自身获得1点快速医疗（12医疗点数）。</p><p>纷落繁花<br> 魔幻本质<br> 价格：B+2500<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：18L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。<br> 描述：这是一柄白粉色的花伞，有着落樱花瓣的装饰与半透明的纱边，散发着淡淡的樱花香气，可以当作阳伞撑开，穿行而过，似有花瓣飘落，淡淡花香传开，令人如沐春风，阳伞收起，也可乘花而去，将敌一剑枭首。<br> 持有该武器时，你获得C级传送移动特性，可以传送移动时，你会瞬间出现在目的地，而原来所在的位置，只剩一捧樱花飘落。<br> 每轮可以有一次，将攻击结合在移动当中，无论如何，只要以该武器进行攻击，所有的特效都会转变为对应颜色的花瓣。<br> 每轮首次移动时，先进行一次不带有其它加成（即仅只有属性技能数值本身与传奇附加）的【风度+专注+回忆】的检定，将这次检定出目*10米移速加入这次移动中。</p><p>扭曲之眼<br> 特异本质<br> 价格：B+2000<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：18L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。<br> 描述：这是由三根触须缠绕而成的枪刃，触须之间不断蠕动纠缠，发出黏腻的粘液粘连声音。持握的手感如同抓着一只滑腻的头足目海鲜，但其内在散发的虚空引力辅助持有者牢牢将其拿稳，转轮彭大，裸露在外的孔洞中则是六颗不断转动的瞳孔，不断地凝视这个世界，每当消耗晶弹，都会有一颗眼球爆裂，发出深晦的低沉哀嚎。<br> 效果：任何目睹这把令人不适的活体武器的生物都会降低二级针对持有者的好感度，可以因此降低为极端；该武器可以为持有者提供基于敏感范围的360°线性强感知，持有者会拥有覆盖360°视角的、基于视觉的额外全景视野，所有的视觉信息会强制进入持有者的脑海，以这把武器对能够精准定位的敌人发起攻击时，攻击加骰额外提升一级（至多8加骰）。这把武器还会为持有者额外提供感知属性相关检定上的1点附加成功。<br> 每轮一次，以一个迅捷动作消耗1点意志额外引爆一颗晶弹，强迫缠绕的触须活性化袭击敌人，使得这一次攻击的触及范围额外提升35米，伴随着这次攻击挥砍而出，触须会伸长并鞭打向目标，武器变化为条尖端生长着尖刃的生物触须砍向触及范围内至多7个目标（即1个主目标与6个额外目标），你也可以选择令所有触须攻击同一个目标，但这只会多造成3点多次攻击减值；承受这次攻击的目标需要以攻击伤害作为dc，额外进行一次意志豁免，承受差值的B级创伤来源恐惧点数。</p><p>业报<br> 魔幻本质<br> 价格：B+2000<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：18L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲3<br> 攻击时若没有附带消耗晶弹的技艺，则可以自由动作扣动扳机来消耗1枚晶弹。<br> 描述：这是一柄银白色的武士刀，刀护的部分被替换为了可以用来装填晶弹的转轮，拔刀进行攻击时，消耗晶弹将会表现为从鞘中爆发作为推力，黑色的握柄极具舒适性；该武器出自于一位来自岛国的刀匠，获得这把武器的剑客在多年以后参加了一场席卷全世界的强者决斗，最终，剑客战斗了七天七夜，他为了活下去，不断地挥刀，为了发挥武器的性能，不断地塞入连他自己都不知道从何而来的子弹，当他的意识恢复清明时，弹仓内的眼球也随之滚落下来……<br> 剑客看着被他屠杀殆尽的百城池，崩溃地选择了自尽。<br> 效果：特殊的，该武器也可以被视为【武士刀】，但仅能以武技-枪刃专业进行攻击检定。<br> 持有该武器进行移动时，若这次移动前进行了【纳刀归鞘】，则可以额外视为进行了一次格挡。<br> 每当你施展一个等级至少为B级的拔刀术连续技技艺或枪刃连续技技艺，这把武器的左侧刀身上就会裂开一道口子，从中生长出不断扫视战场的眼球，当睁开三条裂缝之后，整把刀将会散发出紫黑色的气势，此时解锁施展技艺【今世报】的使用权。<br> 【今世报】：这是一个攻击技，视为一个B级拔刀术技艺与枪刃技艺，施展前，需要【纳刀归鞘】。<br> 以一个标准动作进行一次拔刀术攻击，这次攻击在发起时会立即消耗一颗晶弹作为推力以此为攻击额外提供【破甲5】，拔刀横斩，紫黑色的刀光会基于自身触及范围覆盖前方180°半圆形范围内的所有敌人，这次攻击具有【8加骰】，并额外附带1点不可豁免的流血异常点数，所有承受这次攻击者以伤害作为dc进行意志豁免，未能完全豁免者，其精神将被自身的罪业所沁染，失去心中的矜持与道德，在恐惧与悔恨中开始袭击其他人，业报的持有者可以指定被今世报影响者避开哪些人进行攻击，这是来源于B级影响心灵来源的支配效果影响；从所有未能完全豁免者中选择其一，目标罪恶的内心将被刀刃上的怨力纠缠而出，在原地留下一个紫黑色的模糊魂灵，对魂灵进行的攻击将会传递给魂灵的本体，这是一个B级诅咒来源的【魂牵】特性，以今世报进行攻击造成的影响仅持续一轮。</p><p>A级：</p><p>悠远之息<br> 神话本质<br> 价格：A+4000<br> 武器类别：枪刃<br> 专业：武技-枪刃<br> 武器伤害：27L<br> 伤害类型 ：物理-挥砍<br> 武器体积：3<br> 装弹：6<br> 基础特性：攻击时若消耗了至少1枚晶弹则获得破甲2<br> 描述：“乌鸦啊，我因罪被上天惩戒，这杆枪从天而降刺穿了树干和我的心脏，树也维持了我的生命，你就取走枪头，留我在此赎罪吧。”<br> “乌鸦啊，我因追求永生而变成这副模样，别担心，这些石头和我生长在一起；你既来之，就取走这枚石碑，以作警示吧。”<br> “乌鸦啊，我因傲慢而落入网中，这些蛛丝有着维持猎物生命的力量，而它们的主人却早已饿死，我看着那怪物的尸骸腐朽，你就取走那些眼睛，留我继续在这苟活吧。”<br> ……<br> 乌鸦叼走了一件又一件悠久之物，在几乎永久的时间后，它坐在名为永恒的窝巢里，看着宇宙在眼前寂灭，这让乌鸦第一次开始思考——<br> ……<br> 这是一柄由无数自然物生长而成的武器，由一块石碑作为剑身，苔藓连接了树心转轮和从木质中生长而出的银白剑刃，亘古久远的气息吹拂过转轮中的红玉晶弹，仿佛握住的不是一把武器，而是自己从未见证过的、曾存于不存的历史。<br> 效果：持有该武器会为持有者提供【快速医疗4】（48医疗点数）。<br> 若一次攻击中消耗了晶弹，则承受这次攻击者需要针对这次攻击检定出目进行意志豁免，若豁免失败，则会不可豁免地陷入持续一轮的A级时间停止状态。<br> 每轮一次，你可以在攻击时以自由动作激活武器之中储存的，悠久似永恒的时间中，无数所珍视之物的力量，根据这次攻击消耗的晶弹数量分为三档（1枚/3枚/6枚）获得不同的效果；<br> 1枚：攻击额外获得【8加骰】，敌方以攻击伤害作为dc进行意志豁免，若失败，其在意志豁免上承受【劣化2】。<br> 3枚：在结算此次攻击的效果后，这次攻击武器所经过的位置再次复现出绿色的武器虚影立即对目标再进行一次攻击，这是一次不附带技艺的标准攻击。<br> 6枚：此次攻击造成的伤害提升一倍。<br> 该武器的持有者在身死之时，这把武器之上会蔓延出散发着银色光辉的鸦羽、树木的根须与带着符文的石花，使得持有者的半身被覆盖，定格在死亡的这一刻，遗体仿佛被送入了无限悠远之地，无法被任何手段破坏，损伤。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',31)])])}const B=p(s,[["render",n]]);export{L as __pageData,B as default};
